#include <bits/stdc++.h>

using namespace std;

// Function to count the subarrays where the maximum element is not greater than K
int totalSubarrays(int arr[], int N, int K) {
    int ans = 0, i = 0;

    while (i < N) {
        // If arr[i] > K, arr[i] cannot be part of any valid subarray.
        if (arr[i] > K) {
            i++;
            continue;
        }

        int count = 0;
        // Count the number of consecutive elements that are <= K.
        while (i < N && arr[i] <= K) {
            i++;
            count++;
        }

        // Add the number of subarrays that can be formed from 'count' consecutive elements.
        ans += ((count * (count + 1)) / 2);
    }

    return ans;
}

// Function to count the subarrays where the maximum element is exactly K
int countSubarrays(int arr[], int N, int K) {
    // Count subarrays where the maximum element is <= K-1.
    int count1 = totalSubarrays(arr, N, K - 1);

    // Count subarrays where the maximum element is <= K.
    int count2 = totalSubarrays(arr, N, K);

    // The number of subarrays where the maximum element is exactly K.
    int ans = count2 - count1;

    return ans;
}

